import{_ as e,c as t,o as r,d as a}from"./app.de5d70b2.js";var D="/assets/square.8ce51385.svg";const h='{"title":"12 \u044D\u0442\u0430\u043F\u043E\u0432","description":"","frontmatter":{"title":"12 \u044D\u0442\u0430\u043F\u043E\u0432","icon":"twelve.svg","subtitle":"\u0414\u044E\u0436\u0438\u043D\u0430 \u0448\u0430\u0433\u043E\u0432 \u043D\u0430 \u043F\u0443\u0442\u0438 \u043E\u0442 \u0438\u0434\u0435\u0438 \u0434\u043E \u0435\u0435 \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u0438\u044F","date":"2020-10-01T00:00:00.000Z","color":"#BD8241"},"headers":[],"relativePath":"theory/system/projectapp/twelve/index.md"}',s={},_=a('<p>\u041F\u0440\u043E\u0435\u043A\u0442\u043D\u044B\u0439 \u0446\u0438\u043A\u043B \u0440\u0430\u0437\u0432\u043E\u0440\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u043E \u043C\u0435\u0440\u0435 \u0435\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F. \u041A\u043E\u0433\u0434\u0430 \u0441\u0430\u043C \u0440\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043E\u043C \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u043D\u043E \u0440\u0435\u0430\u043B\u0438\u0437\u0443\u0435\u0448\u044C \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u0440\u043E\u0435\u043A\u0442\u044B \u0446\u0435\u043B\u0438\u043A\u043E\u043C, \u0437\u0430\u043C\u0435\u0447\u0430\u0435\u0448\u044C \u0432\u0441\u0435 \u0431\u043E\u043B\u044C\u0448\u0435 \u0442\u043E\u043D\u043A\u043E\u0441\u0442\u0435\u0439 \u0438 \u0442\u0440\u0443\u0434\u043D\u043E\u0441\u0442\u0435\u0439 \u043D\u0430 \u043F\u0443\u0442\u0438 \u043E\u0442 \u0438\u0434\u0435\u0438 \u0434\u043E \u0435\u0451 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438. \u0421 \u043E\u043F\u044B\u0442\u043E\u043C \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u043F\u043B\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0441\u043B\u043E\u0436\u043D\u044B\u0445 \u0438 \u0434\u043E\u043B\u0433\u043E\u0441\u0440\u043E\u0447\u043D\u044B\u0445 \u043F\u0440\u043E\u0435\u043A\u0442\u043E\u0432, \u0432 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043A\u0430\u0436\u0434\u044B\u0439 \u0448\u0430\u0433 \u2013 \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u043B\u0438\u0448\u044C \u043C\u0430\u043B\u0430\u044F \u0447\u0430\u0441\u0442\u044C \u043E\u0431\u0449\u0435\u0433\u043E \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430, \u043D\u043E \u0438 \u043C\u043E\u0436\u0435\u0442 \u0441\u0430\u043C \u043F\u043E \u0441\u0435\u0431\u0435 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u0442\u044C \u0446\u0435\u043B\u044B\u0439 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u0439 \u043F\u0440\u043E\u0435\u043A\u0442.</p><p>\u0421\u043B\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u043E\u0435\u043A\u0442\u0430 \u043C\u043E\u0436\u0435\u0442 \u0440\u0430\u0441\u0442\u0438 \u0441\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C \u0438 \u0432 \u043A\u0430\u043A\u043E\u0439-\u0442\u043E \u043C\u043E\u043C\u0435\u043D\u0442 \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u0441\u0442\u0430\u0442\u044C \u0443\u0436\u0435 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 \u0432\u0437\u0430\u0438\u043C\u043E\u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0445 \u043F\u0440\u043E\u0435\u043A\u0442\u043E\u0432. \u0412\u0441\u0435 \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043E\u0442 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F.\xA0\u0418 \u044D\u0442\u0443 \u0442\u043E\u0447\u043A\u0443 \u043C\u043E\u0436\u043D\u043E \u043E\u0442\u043A\u0430\u043B\u0438\u0431\u0440\u043E\u0432\u0430\u0442\u044C \u043F\u043E \u0442\u0435\u043A\u0443\u0449\u0435\u0439 \u0441\u043B\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0437\u0430\u0434\u0443\u043C\u0430\u043D\u043D\u043E\u0433\u043E.</p><p>12 \u0448\u0430\u0433\u043E\u0432 - \u044D\u0442\u043E \u0443\u0436\u0435 \u0437\u0430 \u0433\u0440\u0430\u043D\u0438\u0446\u0430\u043C\u0438 \u0440\u0430\u043C\u043E\u043A \u043A\u0440\u0430\u0442\u043A\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u043F\u0430\u043C\u044F\u0442\u0438 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043F\u043E\u043C\u0435\u0449\u0430\u0435\u0442\u0441\u044F <a href="https://ru.wikipedia.org/wiki/%D0%9C%D0%B0%D0%B3%D0%B8%D1%87%D0%B5%D1%81%D0%BA%D0%BE%D0%B5_%D1%87%D0%B8%D1%81%D0%BB%D0%BE_%D1%81%D0%B5%D0%BC%D1%8C_%D0%BF%D0%BB%D1%8E%D1%81-%D0%BC%D0%B8%D0%BD%D1%83%D1%81_%D0%B4%D0%B2%D0%B0" class="external-link" target="_blank" rel="noopener noreferrer">7\xB12 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432</a>. \u041D\u043E <a href="https://ru.wikipedia.org/wiki/12_(%D1%87%D0%B8%D1%81%D0%BB%D0%BE)" class="external-link" target="_blank" rel="noopener noreferrer">\u0447\u0438\u0441\u043B\u043E 12</a> \u0432\u043E \u043C\u043D\u043E\u0433\u043E\u043C \u043E\u0441\u043E\u0431\u0435\u043D\u043D\u043E\u0435. \u042D\u0442\u0430 \u0442\u0430 \u0441\u0430\u043C\u0430\u044F \u0434\u0440\u0435\u0432\u043D\u044F\u044F \u0434\u044E\u0436\u0438\u043D\u0430, \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043B\u0438\u0441\u044C \u0432\u043E \u043C\u043D\u043E\u0433\u0438\u0445 \u0446\u0438\u0432\u0438\u043B\u0438\u0437\u0430\u0446\u0438\u044F\u0445 \u043F\u0440\u043E\u0448\u043B\u043E\u0433\u043E. \u042D\u0442\u043E 12 \u0447\u0430\u0441\u043E\u0432 \u043D\u0430 \u0446\u0438\u0444\u0435\u0440\u0431\u043B\u0430\u0442\u0435, 12 \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0432 \u0433\u043E\u0434\u0443, 12 \u043D\u043E\u0442 \u0432 \u0440\u0430\u0432\u043D\u043E\u043C\u0435\u0440\u043D\u043E\u0439 \u0442\u0435\u043C\u043F\u0435\u0440\u0430\u0446\u0438\u0438. \u0427\u0438\u0441\u043B\u043E 12 \u0434\u0435\u043B\u0438\u0442\u0441\u044F \u043D\u0430 2, \u043D\u0430 3, \u043D\u0430 4 \u0438 \u043D\u0430 6 \u0433\u0440\u0443\u043F\u043F, \u0447\u0442\u043E \u0434\u0435\u043B\u0430\u0435\u0442 \u0435\u0433\u043E \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0443\u0434\u043E\u0431\u043D\u044B\u043C \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u0438\u0435\u043C \u0434\u043B\u044F \u0441\u0438\u0441\u0442\u0435\u043C \u0441\u0447\u0438\u0441\u043B\u0435\u043D\u0438\u044F. \u0422\u0430\u043A \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043E\u0441\u0432\u043E\u0438\u043B \u044D\u0442\u043E \u0447\u0438\u0441\u043B\u043E \u0438 \u043C\u044B \u0432\u0441\u0435 \u0435\u0449\u0435 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043D\u0435\u043F\u043B\u043E\u0445\u043E \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u044B \u043E\u043F\u0435\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043D\u0430\u0431\u043E\u0440\u0430\u043C\u0438 \u0438\u0437 12 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432.</p><p><img src="'+D+'" alt=""></p><p>\u0412\u0441\u0435 12 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432, \u0431\u0443\u0434\u044C \u0442\u043E \u043C\u0435\u0441\u044F\u0446\u044B, \u0447\u0430\u0441\u044B \u0438\u043B\u0438 \u043D\u043E\u0442\u044B, \u0440\u0435\u0434\u043A\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442\u0441\u044F \u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u044E\u0442\u0441\u044F \u043E\u0434\u043D\u0438\u043C \u0446\u0435\u043B\u044B\u043C. \u041C\u044B \u0438\u043D\u0442\u0443\u0438\u0442\u0438\u0432\u043D\u043E \u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u043E \u0432\u044B\u0434\u0435\u043B\u044F\u0435\u043C \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u0433\u0440\u0443\u043F\u043F\u044B \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0435\u0439. 12 \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0433\u043E\u0434\u0430 \u0433\u0440\u0443\u043F\u043F\u0438\u0440\u0443\u044E\u0442\u0441\u044F \u0432 4 \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0433\u043E\u0434\u0430, \u0446\u0438\u0444\u0435\u0440\u0431\u043B\u0430\u0442 \u0434\u0435\u043B\u0438\u0442\u0441\u044F \u0438 \u043D\u0430 60 \u043C\u0438\u043D\u0443\u0442, \u0430 \u0438\u0437 12 \u043D\u043E\u0442 \u043A\u0430\u043A \u043F\u0440\u0430\u0432\u0438\u043B\u043E \u0432\u044B\u0431\u0438\u0440\u0430\u0435\u0442\u0441\u044F \u0442\u043E\u043D\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0438\u0437 5-7 \u0437\u0432\u0443\u043A\u043E\u0432\u044B\u0441\u043E\u0442\u043D\u044B\u0445 \u043A\u043B\u0430\u0441\u0441\u043E\u0432.</p><p>\u0414\u0435\u043B\u0435\u043D\u0438\u0435 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430 \u043D\u0430 12 \u0448\u0430\u0433\u043E\u0432 \u2013 \u044D\u0442\u043E \u0432\u0437\u0433\u043B\u044F\u0434 \u043D\u0435\u043C\u043D\u043E\u0433\u043E \u0441\u043E \u0441\u0442\u043E\u0440\u043E\u043D\u044B. \u0412 \u0441\u0430\u043C\u043E\u043C \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0440\u0430\u0431\u043E\u0442\u044B \u0442\u0430\u043A\u043E\u0439 \u043F\u0435\u0440\u0441\u043F\u0435\u043A\u0442\u0438\u0432\u044B \u0443 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u043D\u0435\u0442. \u041F\u043E\u043C\u043D\u0438\u0442\u044C \u043D\u0430 3-5 \u0448\u0430\u0433\u043E\u0432 \u043D\u0430\u0437\u0430\u0434, \u0443\u0434\u0435\u043B\u044F\u0442\u044C \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u0442\u0435\u043A\u0443\u0449\u0438\u043C \u0437\u0430\u0434\u0430\u0447\u0430\u043C \u0438 \u043F\u0440\u043E\u0434\u0443\u043C\u044B\u0432\u0430\u0442\u044C 3-5 \u0448\u0430\u0433\u043E\u0432 \u043D\u0430\u043F\u0435\u0440\u0435\u0434 \u2013 \u0443\u0436\u0435 \u043A\u0430\u0436\u0435\u0442\u0441\u044F \u0432\u044B\u0437\u043E\u0432\u043E\u043C \u0434\u043B\u044F \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u0439 \u043F\u0441\u0438\u0445\u0438\u043A\u0438. \u0427\u0442\u043E \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C \u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u043F\u043E\u0442\u043E\u043A\u0430, \u043A\u043E\u0433\u0434\u0430 \u043F\u043E\u0440\u043E\u0439 \u0437\u0430\u0431\u044B\u0432\u0430\u0435\u0448\u044C \u0432\u043E\u043E\u0431\u0449\u0435 \u043E \u0447\u0435\u043C-\u043B\u0438\u0431\u043E, \u043A\u0440\u043E\u043C\u0435 \u043F\u0440\u044F\u043C\u043E \u0442\u043E\u0433\u043E,\xA0\u0447\u0435\u043C \u0437\u0430\u043D\u044F\u0442 \u0432 \u0434\u0430\u043D\u043D\u044B\u0439 \u043C\u043E\u043C\u0435\u043D\u0442. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0442\u0430\u043A \u0432\u0430\u0436\u043D\u044B \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u044F, \u0442\u0430\u043A\u0442\u0438\u043A\u0430, \u043C\u0435\u0442\u043E\u0434\u0438\u043A\u0430.</p><p>\u0414\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u0435\u0440\u0438\u0447\u043D\u0443\u044E \u043C\u043E\u0434\u0435\u043B\u044C \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430 \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u0435\u0442 \u0432\u0438\u0434\u0435\u0442\u044C \u0441\u043B\u043E\u0436\u043D\u044B\u0435 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B \u043A\u0430\u043A \u0446\u0435\u043B\u043E\u0435, \u0447\u0442\u043E \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u0435\u0442 \u0434\u0435\u0440\u0436\u0430\u0442\u044C \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0438 \u0442\u0435\u043C\u043F. \u0422\u0430\u043A\u043E\u0435 \u0432\u0438\u0434\u0435\u043D\u0438\u0435 \u043E\u0447\u0435\u043D\u044C \u043F\u043E\u043B\u0435\u0437\u043D\u043E, \u043D\u043E \u043E\u043D\u043E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u043F\u0440\u0438 \u0432\u0437\u0433\u043B\u044F\u0434\u0435 \u0441\u043E \u0441\u0442\u043E\u0440\u043E\u043D\u044B. \u0414\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u043A\u0430\u0436\u0434\u043E\u043C\u0443 \u0436\u0435\u043B\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043E\u0441\u0432\u043E\u0438\u0442\u044C \u043F\u0435\u0440\u0435\u0445\u043E\u0434 \u0432 \u0442\u0430\u043A\u0443\u044E \u043F\u043E\u0437\u0438\u0446\u0438\u044E \u043F\u043E \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044E \u043A \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438. \u0412\u044B\u0434\u0435\u043B\u044F\u0442\u044C \u0432\u0440\u0435\u043C\u044F \u0434\u043B\u044F \u0430\u043D\u0430\u043B\u0438\u0437\u0430 \u0438 \u043F\u043B\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0441 \u0431\u043B\u043E\u043A\u043D\u043E\u0442\u043E\u043C \u0438\u043B\u0438 \u043A\u043E\u043C\u043F\u044C\u044E\u0442\u0435\u0440\u043E\u043C, \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u0441 \u043A\u0443\u0440\u0430\u0442\u043E\u0440\u0430\u043C\u0438,\xA0\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043D\u0430\u0441\u0442\u0440\u043E\u0435\u043D\u044B \u0432\u0438\u0434\u0435\u0442\u044C \u043F\u0440\u043E\u0435\u043A\u0442\u044B \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u043D\u043E \u0438 \u043F\u043E\u043C\u043E\u0433\u0430\u044E\u0442 \u0432 \u043D\u0438\u0445 \u0431\u044B\u0441\u0442\u0440\u043E \u0441\u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u0438 \u043D\u0435 \u0437\u0430\u0431\u043B\u0443\u0434\u0438\u0442\u044C\u0441\u044F.</p>',7),o=[_];function p(i,n,B,c,l,d){return r(),t("div",null,o)}var k=e(s,[["render",p]]);export{h as __pageData,k as default};
